192→/* ── Form Styles ── */
193→.auth-form {
194→    display: flex;
195→    flex-direction: column;
196→    gap: 20px;
197→}
198→
199→.form-field {
200→    display: flex;
201→    flex-direction: column;
202→    gap: 8px;
203→}
