233→}
234→
235→.auth-input:hover {
236→    border-color: var(--border-light);
237→}
238→
239→.auth-input:focus {
240→    outline: none;
241→    border-color: var(--accent-amber);
242→    box-shadow: 0 0 0 3px rgba(212, 168, 83, 0.12);
243→    background: var(--bg-primary);
244→}
