264→    font-weight: 600;
265→    letter-spacing: 0.04em;
266→    text-transform: uppercase;
267→    color: var(--text-muted);
268→    cursor: pointer;
269→    padding: 6px 10px;
270→    border-radius: 4px;
271→    transition:
272→        background-color 0.15s ease,
